#include <iostream>

int main() {
    int a, b, c, d;
    std::cin >> a >> b >> c >> d;

    std::cout << "expr1: " << (a + b * c - d)   << '\n';
    std::cout << "expr2: " << (a * b + c * d)   << '\n';
    std::cout << "expr3: " << (a - b - c)       << '\n';
    std::cout << "expr4: " << (a + b * c % d)   << '\n';

    return 0;
}

