exercises.solution_code:
#include <iostream>

int main() {
    std::cout << std::boolalpha;

    int x, mask, threshold;
    std::cin >> x >> mask >> threshold;

    std::cout << "check1: " << ((x & mask) == 0)                    << '\n';
    std::cout << "check2: " << (x > threshold && mask != 0)         << '\n';
    std::cout << "check3: " << (x + mask > threshold || mask == 0)  << '\n';
    std::cout << "check4: " << (!(x == mask))                       << '\n';
    std::cout << "check5: " << (x >= 0 && x <= 255 && mask >= 0)   << '\n';

    return 0;
}
